description:
## Bug Report

Please answer these questions before submitting your issue. Thanks!

An interesting note is that this bug is largely due to the ZEROFILL keyword which causes this inconsistency to occur on both MySQL and MariaDB which have verified that TiDB results are inconsistent.

### 1. Minimal reproduce step (Required)
-----------------------------------------------------

DROP DATABASE IF EXISTS database3;
CREATE DATABASE database3;
USE database3;
CREATE TABLE t0(c0 TINYINT(1) ZEROFILL NOT NULL );
CREATE TABLE t1(c0 NUMERIC ZEROFILL NOT NULL );
REPLACE INTO t0 VALUES (false), (false);

INSERT IGNORE  INTO t0(c0) VALUES (false), (false), (true) ON DUPLICATE KEY UPDATE c0=(CASE t0.c0 WHEN t0.c0 THEN t0.c0 ELSE t0.c0 END );
REPLACE INTO t0(c0) VALUES (false);
INSERT IGNORE  INTO t1 VALUES (1762725494);
UPDATE t0 SET c0=true WHERE t0.c0;

REPLACE INTO t1(c0) VALUES (266050840);
INSERT IGNORE  INTO t1(c0) VALUES (-2079760622);
REPLACE INTO t0 VALUES (false);
REPLACE INTO t1(c0) VALUES (668150601);

INSERT IGNORE  INTO t1(c0) VALUES (-1193593820), (-767274454);

INSERT INTO t0 VALUES (false), (false) ON DUPLICATE KEY UPDATE c0=false;
UPDATE t0 SET c0=t0.c0 WHERE t0.c0;

REPLACE INTO t0 VALUES (false);

INSERT INTO t0(c0) VALUES (false), (false), (false);
INSERT IGNORE  INTO t0(c0) VALUES (false);

INSERT HIGH_PRIORITY IGNORE  INTO t1 VALUES (1309491249), (723495142) ON DUPLICATE KEY UPDATE c0=true;
REPLACE INTO t0 VALUES (false);
INSERT IGNORE  INTO t1 VALUES (-1682760061), (-1627235536) ON DUPLICATE KEY UPDATE c0=t1.c0;
REPLACE INTO t0(c0) VALUES (false), (true), (true);
REPLACE INTO t0 VALUES (false);
INSERT INTO t1 VALUES (614089779);
REPLACE INTO t0(c0) VALUES (false);
CREATE INDEX i0 ON t0(c0);

REPLACE INTO t1 VALUES (1904619520);
REPLACE INTO t0(c0) VALUES (true), (true);

INSERT IGNORE  INTO t1(c0) VALUES (-1414511750);

INSERT INTO t1(c0) VALUES (900556266);
INSERT IGNORE  INTO t1(c0) VALUES (-729137058);

INSERT IGNORE  INTO t1 VALUES (677535021) ON DUPLICATE KEY UPDATE c0=(~ ((NOT (((NULL)OR(t1.c0))))));

-- The SQL statement that triggered the bug

SELECT DISTINCT t0.c0, t1.c0 FROM  t0 INNER JOIN t1 ON ((BIN(-928375337))<=(t0.c0));

(SELECT DISTINCT t0.c0, t1.c0 FROM  t0 LEFT JOIN t1 ON ((BIN(-928375337))<=(t0.c0))) INTERSECT (SELECT DISTINCT t0.c0, t1.c0 FROM  t0 RIGHT JOIN t1 ON ((BIN(-928375337))<=(t0.c0)));


<!-- a step by step guide for reproducing the bug. -->

### 2. What did you expect to see? (Required)
SELECT DISTINCT t0.c0, t1.c0 FROM  t0 INNER JOIN t1 ON ((BIN(-928375337))<=(t0.c0));    -- cardinality: 0

-- (SELECT DISTINCT t0.c0, t1.c0 FROM  t0 LEFT JOIN t1 ON ((BIN(-928375337))<=(t0.c0))) INTERSECT (SELECT DISTINCT t0.c0, t1.c0 FROM  t0 RIGHT JOIN t1 ON ((BIN(-928375337))<=(t0.c0)));    -- cardinality: 0

### 3. What did you see instead (Required)
SELECT DISTINCT t0.c0, t1.c0 FROM  t0 INNER JOIN t1 ON ((BIN(-928375337))<=(t0.c0));    -- cardinality: 20

-- (SELECT DISTINCT t0.c0, t1.c0 FROM  t0 LEFT JOIN t1 ON ((BIN(-928375337))<=(t0.c0))) INTERSECT (SELECT DISTINCT t0.c0, t1.c0 FROM  t0 RIGHT JOIN t1 ON ((BIN(-928375337))<=(t0.c0)));    -- cardinality: 0
